import java.io.*;
import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = br.readLine();

            // Sanitize and escape user input before displaying it
            String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);
            System.out.println("<h1>Welcome, " + sanitizedInput + "!</h1>");
        } catch (IOException e) {
            System.err.println("Error reading user input");
        }
    }
}

